FROM jsonb_to_recordset('[{"id": "cap-106-chinese-029", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列詩句前後兩句的關係，何者說明正確？", "options": ["美酒飲教微醉後，好花看到半開時――前句為因，後句為果", "戲掬清泉灑蕉葉，兒童誤認雨聲來――前句泉灑蕉葉的假設引發後句的雨聲", "書冊埋頭無了日，不如拋卻去尋春――將前句的讀書與後句的尋春互作比較", "梅須遜雪三分白，雪卻輸梅一段香――前句由梅至雪，後句由雪至香，層層遞進"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 29, "raw_text": "29.   下列詩句前後兩句的關係，何者說明正確？\n      (A)美酒飲教微醉後，好花看到半開時――前句為因，後句為果\n      (B)戲掬清泉灑蕉葉，兒童誤認雨聲來――前句泉灑蕉葉的假設引發後句的雨聲\n      (C)書冊埋頭無了日，不如拋卻去尋春――將前句的讀書與後句的尋春互作比較\n      (D)梅須遜雪三分白，雪卻輸梅一段香――前句由梅至雪，後句由雪至香，層層遞進\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-030", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "右列是某小說中的謎語，其中哪一句未使用\n代詞？", "options": ["古老智慧之謎可解於此 \u001b\u001a\u0019\u0018\u0017\u0016，", "力助吾輩保伊全家團圓           \u0014\u0013\u0012\u0011\u0010\u000f\u000e   ，", "聖殿騎士之碑是為關鍵             \b\u0007\u001b\u0006\u0005\u0004\u0003\u0002，", "阿特巴希為汝真相展現           \u0001\u0004 ­。"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 30, "raw_text": "30. 右列是某小說中的謎語，其中哪一句未使用\n    代詞？\n    (A)古老智慧之謎可解於此           \u001f\n\n\n\u001b\u001a\u0019\u0018\u0017\u0016，\n    (B)力助吾輩保伊全家團圓           \u0014\u0013\u0012\u0011\u0010\u000f\u000e   ，\n    (C)聖殿騎士之碑是為關鍵             \b\u0007\u001b\u0006\u0005\u0004\u0003\u0002，\n    (D)阿特巴希為汝真相展現           \u0001\u0004 ­。\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-031", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「我曾經踮起腳尖遠望，結果遠不如登上高處看得廣；我登上高處向人招手，胳臂\n並沒有加長，但遠處的人也能看得見；順著風呼喊，聲音沒有更加激昂，但聽的人\n卻能聽得很清楚。因此，在學習的道路上，要______________________。」文中\n畫線處最適合填入下列何者？", "options": ["善用周遭資源，以收事半功倍之效", "立定遠大目標，確立人生未來方向", "勇於多方嘗試，才能激發自我潛能", "慎選學習夥伴，以免日後誤入歧途"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 31, "raw_text": "31. 「我曾經踮起腳尖遠望，結果遠不如登上高處看得廣；我登上高處向人招手，胳臂\n    並沒有加長，但遠處的人也能看得見；順著風呼喊，聲音沒有更加激昂，但聽的人\n    卻能聽得很清楚。因此，在學習的道路上，要______________________。」文中\n    畫線處最適合填入下列何者？\n    (A)善用周遭資源，以收事半功倍之效\n    (B)立定遠大目標，確立人生未來方向\n    (C)勇於多方嘗試，才能激發自我潛能\n    (D)慎選學習夥伴，以免日後誤入歧途\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-032", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「桃符仰視艾人而罵曰：『汝何等草芥，輒居我上？』艾人俯而應曰：『自元日\n至端午以來，汝已半截入土，猶爭高下乎？』桃符怒，往復紛然不已。門神解\n之曰：『吾輩不肖，方傍人門戶，何暇爭閒氣耶？』」根據這段文字，下列敘\n述何者正確？", "options": ["艾人以「半截入土」暗譏桃符有過時之嫌", "門神指責桃符愛爭閒氣，所以只能傍人門戶", "三者位置由高而低依序是：門神、桃符、艾人", "桃符與艾人為了元日、端午的重要性而爭吵不休"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 32, "raw_text": "32. 「桃符仰視艾人而罵曰：『汝何等草芥，輒居我上？』艾人俯而應曰：『自元日\n    至端午以來，汝已半截入土，猶爭高下乎？』桃符怒，往復紛然不已。門神解\n    之曰：『吾輩不肖，方傍人門戶，何暇爭閒氣耶？』」根據這段文字，下列敘\n    述何者正確？\n    (A)艾人以「半截入土」暗譏桃符有過時之嫌\n    (B)門神指責桃符愛爭閒氣，所以只能傍人門戶\n    (C)三者位置由高而低依序是：門神、桃符、艾人\n    (D)桃符與艾人為了元日、端午的重要性而爭吵不休\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-033", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「以往許多民生用品都以農作物製成，取之於大自然，還之於大自然，不會造\n成地球負擔、環境汙染。若更用心研發，一定可以製作得更精良、推廣得更普\n及。很可惜在工業產品的衝擊下，這些用品一一被取代而消失。」根據這段文\n字，下列何者最符合作者的觀點？", "options": ["近代快速工業化導致農作物大量消失", "用心研發的農作物不會造成地球負擔", "以農作物製成的產品較工業產品更為精良", "將農作物轉加利用更能夠保護我們的地球"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 33, "raw_text": "33. 「以往許多民生用品都以農作物製成，取之於大自然，還之於大自然，不會造\n    成地球負擔、環境汙染。若更用心研發，一定可以製作得更精良、推廣得更普\n    及。很可惜在工業產品的衝擊下，這些用品一一被取代而消失。」根據這段文\n    字，下列何者最符合作者的觀點？\n    (A)近代快速工業化導致農作物大量消失\n    (B)用心研發的農作物不會造成地球負擔\n    (C)以農作物製成的產品較工業產品更為精良\n    (D)將農作物轉加利用更能夠保護我們的地球\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-034", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列文句，何者詞語使用正確？", "options": ["放學後學生們各自返家，殊途同歸", "母親過世後，她傷心欲絕，如喪考妣", "她對這次的展覽品如數家珍，十分熟悉", "這對雙胞胎謙和有禮，情同手足，令人稱羨"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 34, "raw_text": "34. 下列文句，何者詞語使用正確？\n    (A)放學後學生們各自返家，殊途同歸\n    (B)母親過世後，她傷心欲絕，如喪考妣\n    (C)她對這次的展覽品如數家珍，十分熟悉\n    (D)這對雙胞胎謙和有禮，情同手足，令人稱羨\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-035", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列對於ADHD者的敘述，何者最符合作者原意？", "options": ["發明家往往是ADHD者", "不宜以異類眼光看待ADHD者", "ADHD者擁有比一般人優秀的基因", "缺乏打獵機會是現代ADHD者的悲哀"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 35, "raw_text": "35.   下列對於ADHD者的敘述，何者最符合作者原意？\n      (A)發明家往往是ADHD者\n      (B)不宜以異類眼光看待ADHD者\n      (C) ADHD者擁有比一般人優秀的基因\n      (D)缺乏打獵機會是現代ADHD者的悲哀\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-036", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列敘述，何者與本文內涵最不相關？", "options": ["強調現代人應培養多元能力，以順應社會趨勢", "推測ADHD者的特徵可上溯自遠古人類的行為", "引述學者意見，說明注意力缺失者的行為特徵", "呼籲教育者應以寬廣的視角引領孩子適性發展"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 36, "raw_text": "36.   下列敘述，何者與本文內涵最不相關？\n      (A)強調現代人應培養多元能力，以順應社會趨勢\n      (B)推測ADHD者的特徵可上溯自遠古人類的行為\n      (C)引述學者意見，說明注意力缺失者的行為特徵\n      (D)呼籲教育者應以寬廣的視角引領孩子適性發展\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-037", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "根據本文，莫那魯道在接受紋面前，心情有種難以抑止的澎湃，其原因最不可能為\n下列何者？", "options": ["通過種種考驗之後的欣慰", "即將成為勇士的興奮感受", "為即將執行出草任務而期待", "將承擔部落重任而覺得驕傲"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-37", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 37, "raw_text": "37.   根據本文，莫那魯道在接受紋面前，心情有種難以抑止的澎湃，其原因最不可能為\n      下列何者？\n      (A)通過種種考驗之後的欣慰\n      (B)即將成為勇士的興奮感受\n      (C)為即將執行出草任務而期待\n      (D)將承擔部落重任而覺得驕傲\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-038", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "根據本文，下列敘述何者正確？", "options": ["在賽德克族內，男女戀愛及婚嫁須經過頭目的准許", "賽德克族人的額紋，象徵著生命的至高尊嚴與榮耀", "已屆婚齡卻不結婚的賽德克•巴萊，被視為一種恥辱", "女性想成為賽德克•巴萊，須精通編織的知識與技術"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-37", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 38, "raw_text": "38.   根據本文，下列敘述何者正確？\n      (A)在賽德克族內，男女戀愛及婚嫁須經過頭目的准許\n      (B)賽德克族人的額紋，象徵著生命的至高尊嚴與榮耀\n      (C)已屆婚齡卻不結婚的賽德克•巴萊，被視為一種恥辱\n      (D)女性想成為賽德克•巴萊，須精通編織的知識與技術\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-039", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "根據本文，讀書人與統治者的關係，下列敘述何者正確？", "options": ["建安文人多數成為有權的府主", "中唐文人多在華貴階級中作客", "五代文人以文章推翻世族社會", "北宋文人以寫詩晉身統治階層"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-39", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 39, "raw_text": "39.   根據本文，讀書人與統治者的關係，下列敘述何者正確？\n      (A)建安文人多數成為有權的府主\n      (B)中唐文人多在華貴階級中作客\n      (C)五代文人以文章推翻世族社會\n      (D)北宋文人以寫詩晉身統治階層\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-040", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "關於本文的寫作手法，下列敘述何者正確？", "options": ["以唐和五代文人做對比，凸顯唐代文人的風骨", "透過細膩的空間描寫，以呈現社會組織的變遷", "援引李白、杜甫為例，說明科舉與文人的關係", "按歷史朝代先後次序進行論述，鋪陳文章主旨"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-39", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 40, "raw_text": "40.   關於本文的寫作手法，下列敘述何者正確？\n      (A)以唐和五代文人做對比，凸顯唐代文人的風骨\n      (B)透過細膩的空間描寫，以呈現社會組織的變遷\n      (C)援引李白、杜甫為例，說明科舉與文人的關係\n      (D)按歷史朝代先後次序進行論述，鋪陳文章主旨\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-041", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列針對手足關係的描述，何者最符合本文的觀點？", "options": ["兄弟姊妹是世上少數可以共享兒時記憶的人", "因共同的成長背景，手足間的命運緊緊纏繞", "照顧年邁雙親的責任，必須由兄弟共同承擔", "手足不宜分家獨立，以免相忘於人生的荒漠"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-41", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 41, "raw_text": "41.   下列針對手足關係的描述，何者最符合本文的觀點？\n      (A)兄弟姊妹是世上少數可以共享兒時記憶的人\n      (B)因共同的成長背景，手足間的命運緊緊纏繞\n      (C)照顧年邁雙親的責任，必須由兄弟共同承擔\n      (D)手足不宜分家獨立，以免相忘於人生的荒漠\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-042", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "關於本文的寫作手法，下列敘述何者錯誤？", "options": ["首段由朋友、情人、夫妻的關係起筆，帶出手足間的情誼", "第二段連用兩個反詰句，強調兄弟間深厚的情誼不可磨滅", "前兩段多處使用重複的字詞與類似的句型，可以強化語氣", "末段以雨樹為喻，描寫手足間看似疏離卻同根相連的關係"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-106-chinese-passage-41", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 42, "raw_text": "42.   關於本文的寫作手法，下列敘述何者錯誤？\n      (A)首段由朋友、情人、夫妻的關係起筆，帶出手足間的情誼\n      (B)第二段連用兩個反詰句，強調兄弟間深厚的情誼不可磨滅\n      (C)前兩段多處使用重複的字詞與類似的句型，可以強化語氣\n      (D)末段以